      <style>{`
        * { box-sizing: border-box; margin: 0; padding: 0; }
        .ww-root { font-family: 'Segoe UI', system-ui, -apple-system, sans-serif; background: #05080c; color: #d9e7f7; height: 100vh; overflow: hidden; display: flex; flex-direction: column; }
